def _dbt_process_to_nested(dbt_process: DbtProcess) -> DbtProcessNested:
    """Convert flat DbtProcess to nested format."""
    attrs = DbtProcessAttributes()
    _populate_dbt_process_attrs(attrs, dbt_process)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dbt_process, _DBT_PROCESS_REL_FIELDS, DbtProcessRelationshipAttributes
    )
    return DbtProcessNested(
        guid=dbt_process.guid,
        type_name=dbt_process.type_name,
        status=dbt_process.status,
        version=dbt_process.version,
        create_time=dbt_process.create_time,
        update_time=dbt_process.update_time,
        created_by=dbt_process.created_by,
        updated_by=dbt_process.updated_by,
        classifications=dbt_process.classifications,
        classification_names=dbt_process.classification_names,
        meanings=dbt_process.meanings,
        labels=dbt_process.labels,
        business_attributes=dbt_process.business_attributes,
        custom_attributes=dbt_process.custom_attributes,
        pending_tasks=dbt_process.pending_tasks,
        proxy=dbt_process.proxy,
        is_incomplete=dbt_process.is_incomplete,
        provenance_type=dbt_process.provenance_type,
        home_id=dbt_process.home_id,
        depth=dbt_process.depth,
        immediate_upstream=dbt_process.immediate_upstream,
        immediate_downstream=dbt_process.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dbt_process_from_nested(nested: DbtProcessNested) -> DbtProcess:
    """Convert nested format to flat DbtProcess."""
    attrs = (
        nested.attributes if nested.attributes is not UNSET else DbtProcessAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DBT_PROCESS_REL_FIELDS,
        DbtProcessRelationshipAttributes,
    )
    return DbtProcess(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_dbt_process_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dbt_process_to_nested_bytes(dbt_process: DbtProcess, serde: Serde) -> bytes:
    """Convert flat DbtProcess to nested JSON bytes."""
    return serde.encode(_dbt_process_to_nested(dbt_process))


def _dbt_process_from_nested_bytes(data: bytes, serde: Serde) -> DbtProcess:
    """Convert nested JSON bytes to flat DbtProcess."""
    nested = serde.decode(data, DbtProcessNested)
    return _dbt_process_from_nested(nested)


